+/// Return true if there is a sub instruction linking V1 and V2 (sub V1, V2 or
+/// sub V2, V1) and that sub is known non-zero.
+static bool isNonEqualSub(const Value *V1, const Value *V2,
+                          const APInt &DemandedElts,
+                          const SimplifyQuery &Q, unsigned Depth) {
+  // Look for sub V1, V2
+  for (const User *U : V1->users()) {
+    if (const BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
+      if (BO->getOpcode() == Instruction::Sub &&
+          BO->getOperand(0) == V1 && BO->getOperand(1) == V2)
+        return isKnownNonZero(BO, DemandedElts, Q, Depth + 1);
+    }
+  }
+  // Look for sub V2, V1
+  for (const User *U : V2->users()) {
+    if (const BinaryOperator *BO = dyn_cast<BinaryOperator>(U)) {
+      if (BO->getOpcode() == Instruction::Sub &&
+          BO->getOperand(0) == V2 && BO->getOperand(1) == V1)
+        return isKnownNonZero(BO, DemandedElts, Q, Depth + 1);
+    }
+  }
+  return false;
+}

